 1	import * as React from 'react';
 2	import { kialiStyle } from '../../styles/StyleUtils';
 3	import { useKialiTranslation } from '../../utils/I18nUtils';
 4	import { Button, ButtonVariant, Tooltip } from '@patternfly/react-core';
 5	import { KialiIcon } from 'config/KialiIcon';
 6	import CopyToClipboard from 'react-copy-to-clipboard';
 7	import { download } from '../../utils/Common';
 8	
 9	const configTitleStyle = (includeTitle?: boolean): string =>
10	  kialiStyle({
11	    display: 'flex',
12	    justifyContent: includeTitle ? 'space-between' : 'flex-end'
13	  });
14	
15	const iconStyle = kialiStyle({
16	  marginLeft: '0.25rem'
17	});
18	
19	const downloadButtonStyle = kialiStyle({
20	  marginLeft: '0.5rem'
21	});
22	
23	interface ConfigButtonsTargetPanelProps {
24	  copyText: string;
25	  includeTitle?: boolean;
26	  targetName: string;
27	}
28	
29	export const ConfigButtonsTargetPanel: React.FC<ConfigButtonsTargetPanelProps> = ({
30	  copyText,
31	  includeTitle = true,
32	  targetName
33	}) => {
34	  const [copied, setCopied] = React.useState<boolean>(false);
35	
36	  const { t } = useKialiTranslation();
37	
38	  return (
39	    <>
40	      <div className={configTitleStyle(includeTitle)}>
41	        {includeTitle && <span>{t('Configuration:')}</span>}
42	        <div>
43	          <Tooltip
44	            content={<>{t(copied ? 'Copied' : 'Copy configuration')}</>}
45	            onTooltipHidden={() => setCopied(false)}
46	          >
47	            <CopyToClipboard text={copyText}>
48	              <Button variant={ButtonVariant.link} aria-label={t('Copy')} isInline onClick={() => setCopied(true)}>
49	                <KialiIcon.Copy />
50	                <span className={iconStyle}>{t('Copy')}</span>
51	              </Button>
52	            </CopyToClipboard>
53	          </Tooltip>
54	
55	          <Tooltip content={<>{t('Download configuration in a file')}</>}>
56	            <Button
57	              variant={ButtonVariant.link}
58	              isInline
59	              aria-label={t('Download')}
60	              className={downloadButtonStyle}
61	              onClick={() => download(copyText, `configuration_${targetName}.yaml`)}
62	            >
63	              <KialiIcon.Download />
64	              <span className={iconStyle}>{t('Download')}</span>
65	            </Button>
66	          </Tooltip>
67	        </div>
68	      </div>
69	    </>
70	  );
71	};

